import React, { useState } from 'react';
import Container from '@mui/material/Container';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import MUITheme from './components/MUITheme';
import './styles/claude-theme.css';

import FileUpload from './components/FileUpload';



const annex3Questions = [
    {
        question: 'Is Background (existing knowledge) of TNO required to achieve the TNO Results or do you (basically) start from scratch? If yes, please describe/specify the Background.',
        answer: ''
    },
    {
        question: 'Does TNO have the required access rights to the needed Background? In other words: is TNO not limited to use and give access rights to its Background due to other contractual obligations (e.g. licenses)?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to TNO Background for the implementation of the Project?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to TNO Background to be able to use their Results after the Project?',
        answer: ''
    },
    {
        question: 'Does TNO need access rights to Background or Results of partners for the implementation of the Project?',
        answer: ''
    },
    {
        question: 'What will be the Results (in terms of IPR/Foreground) for TNO?',
        answer: ''
    },
    {
        question: 'Do partners need access rights to the TNO Results to be able to use their Results of the project after the Project?',
        answer: ''
    },
    {
        question: 'Will TNO realize the Results on its own or will other Partners also create and own part of these Results (resulting in Joint IP)? Please specify.',
        answer: ''
    },
    {
        question: 'Will the TNO Results be able to operate on itself after the project or is access to Background or Results of other Partners necessary to be able to use these Results?',
        answer: ''
    },
];

const App: React.FC = () => {
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    // In a real app, answers would be set after processing the file
    const [answers, setAnswers] = useState(annex3Questions);
    const [openIndexes, setOpenIndexes] = useState<number[]>([]);

    const toggleOpen = (idx: number) => {
        setOpenIndexes((prev) =>
            prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]
        );
    };

    const handleFileSelected = (file: File) => {
        setSelectedFile(file);
        // setAnswers([]); // Reset or trigger processing here
    };

    return (
        <MUITheme>
            <Box sx={{ minHeight: '100vh', bgcolor: 'background.default', display: 'flex', flexDirection: 'column' }}>
                <Box component="header" sx={{ bgcolor: 'primary.main', color: '#fff', py: 5, textAlign: 'center', boxShadow: 2 }}>
                    <img src="/logo192.png" alt="EPIFs Assistant Logo" style={{ width: 72, height: 72, marginBottom: 12 }} />
                    <Typography variant="h3" fontWeight={700} mb={1} letterSpacing={1}>
                        EPIFs Assistant
                    </Typography>
                    <Typography variant="subtitle1" color="#e3eafc">
                        Upload your document and get instant answers to your questionnaire.
                    </Typography>
                </Box>
                <Container maxWidth="md" sx={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', pt: 4, pb: 2 }}>
                    <Card sx={{ width: '100%', maxWidth: 480, mb: 3, boxShadow: 4, borderRadius: 3 }}>
                        <CardContent>
                            <FileUpload onFileSelected={handleFileSelected} />
                            {selectedFile && (
                                <Box display="flex" alignItems="center" gap={1} mt={2} bgcolor="#e3eafc" borderRadius={2} px={2} py={1}>
                                    <span style={{ fontSize: '1.3rem' }}>📄</span>
                                    <Typography fontWeight={600}>{selectedFile.name}</Typography>
                                    <Typography color="#7a8ca3" fontSize="0.98rem">({(selectedFile.size / 1024).toFixed(1)} KB)</Typography>
                                </Box>
                            )}
                        </CardContent>
                    </Card>
                    <Card sx={{ width: '100%', maxWidth: 700, boxShadow: 4, borderRadius: 3 }}>
                        <CardContent>
                            <Typography variant="h5" fontWeight={700} color="primary" mb={2}>
                                Annex 3 Questions
                            </Typography>
                            <Box>
                                {answers.map((item, idx) => {
                                    const isOpen = openIndexes.includes(idx);
                                    return (
                                        <Box
                                            key={idx}
                                            onClick={() => toggleOpen(idx)}
                                            sx={{
                                                mb: 2,
                                                borderRadius: 2,
                                                boxShadow: isOpen ? 3 : 1,
                                                bgcolor: isOpen ? 'background.paper' : '#f0f4ff',
                                                cursor: 'pointer',
                                                transition: 'box-shadow 0.2s, background 0.2s',
                                                overflow: 'hidden',
                                            }}
                                        >
                                            <Box sx={{ p: 2, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                                <Typography fontWeight={600} color="primary" sx={{ flex: 1, fontSize: '1.08rem' }}>
                                                    {item.question}
                                                </Typography>
                                                <Typography color="primary" fontWeight={400} fontSize="1.2em" ml={2}>
                                                    {isOpen ? '▲' : '▼'}
                                                </Typography>
                                            </Box>
                                            {isOpen && (
                                                <Box sx={{ bgcolor: '#fff', borderTop: '1px solid #e3eafc', px: 2, pb: 2, animation: 'fadeIn 0.4s cubic-bezier(.4,0,.2,1)' }}>
                                                    <Typography color="text.secondary" fontSize="1.05rem">
                                                        {selectedFile ? item.answer || <span className="placeholder-text">(No answer extracted)</span> : <span className="placeholder-text">(Answer will appear here)</span>}
                                                    </Typography>
                                                    {/* Heuristics placeholder: add logic here to show hints, confidence, or suggestions */}
                                                </Box>
                                            )}
                                        </Box>
                                    );
                                })}
                            </Box>
                        </CardContent>
                    </Card>
                </Container>
                <Box component="footer" sx={{ textAlign: 'center', py: 2, color: '#7a8ca3', fontSize: '0.98rem', mt: 'auto' }}>
                    © {new Date().getFullYear()} EPIFs Assistant. All rights reserved.
                </Box>
            </Box>
        </MUITheme>
    );
};

export default App;
